import math


class Solution:
    def countBeautifulPairs(self, nums):
        def first_digit(x):
            while x >= 10:
                x //= 10
            return x
        count = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                a = first_digit(nums[i])
                b = nums[j] % 10
                if math.gcd(a, b) == 1:
                    count += 1
        return count

