var countBeautifulPairs = function(nums) {
    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
    let count = 0;
    const n = nums.length;
    for (let i = 0; i < n; i++) {
        let a = nums[i];
        while (a >= 10) a = Math.floor(a / 10);
        for (let j = i + 1; j < n; j++) {
            const b = nums[j] % 10;
            if (gcd(a, b) === 1) count++;
        }
    }
    return count;
};
